/** Convert display name to snake_case key for matching backtest results */
function toSnakeCase(name) {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
}

function StrategyCard({ strat, dir, liveData }) {
  const dirColor = dir === 'LONG' ? T.green : T.red
  // Overlay live metrics if available, fall back to hardcoded
  const wr = liveData ? liveData.win_rate : strat.wr
  const pf = liveData ? liveData.profit_factor : strat.pf
  const trades = liveData ? liveData.count : strat.trades
  const sharpe = liveData ? liveData.sharpe : null
  const isLive = !!liveData
  return (
    <div style={{
      background: T.surface, border: `1px solid ${T.border}`, borderRadius: 10,
      padding: 20, transition: 'border-color 0.25s, transform 0.25s',
      display: 'flex', flexDirection: 'column',
    }}
    onMouseEnter={e => { e.currentTarget.style.borderColor = dirColor + '55'; e.currentTarget.style.transform = 'translateY(-2px)'; }}
    onMouseLeave={e => { e.currentTarget.style.borderColor = T.border; e.currentTarget.style.transform = 'none'; }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 }}>
        <h3 style={{ fontSize: 14, fontWeight: 700, color: T.textPrimary, margin: 0 }}>{strat.name}</h3>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexShrink: 0, marginLeft: 8 }}>
          {isLive && (
            <span style={{
              fontSize: 10, fontWeight: 700, padding: '3px 6px', borderRadius: 6,
              background: T.green + '18', color: T.green, fontFamily: T.monoFont,
            }}>LIVE</span>
          )}
          <span style={{
            fontSize: 10, fontWeight: 800, padding: '3px 8px', borderRadius: 6,
            background: dirColor + '18', color: dirColor, fontFamily: T.monoFont,
          }}>{dir}</span>
        </div>
      </div>
      <p style={{ fontSize: 13, color: T.textSecondary, lineHeight: 1.5, margin: '0 0 16px', flex: 1 }}>
        {strat.desc}
      </p>
      <div style={{
        display: 'flex', justifyContent: 'space-between',
        borderTop: `1px solid ${T.border}`, paddingTop: 12,
        fontFamily: T.monoFont, fontSize: 13,
      }}>
        <div>
          <span style={{ color: T.textSecondary, fontSize: 10 }}>Win Rate</span>
          <div style={{ color: T.green, fontWeight: 700 }}>{wr}%</div>
        </div>
        <div>
          <span style={{ color: T.textSecondary, fontSize: 10 }}>Profit Factor</span>
          <div style={{ color: T.blue, fontWeight: 700 }}>{pf}x</div>
        </div>
        <div>
          <span style={{ color: T.textSecondary, fontSize: 10 }}>Trades</span>
          <div style={{ color: T.textPrimary, fontWeight: 700 }}>{trades}</div>
        </div>
        {sharpe !== null && (
          <div>
            <span style={{ color: T.textSecondary, fontSize: 10 }}>Sharpe</span>
            <div style={{ color: sharpe > 0.5 ? T.green : sharpe > 0 ? T.amber : T.red, fontWeight: 700 }}>{sharpe}</div>
          </div>
        )}
      </div>
    </div>
  )
}

